function areAnagramsBruteForce(firstWord, secondWord) {
  const firstWordLength = firstWord.length;
  const secondWordLength = secondWord.length;

  // Anagrams must be of same length
  if (firstWordLength !== secondWordLength) {
    return false;
  }

  // Convert the second word into an array of characters
  let secondWordCharacters = secondWord.split('');

  for (let firstWordIndex = 0; firstWordIndex < firstWordLength; firstWordIndex++) {
    const characterFromFirstWord = firstWord[firstWordIndex];
    let foundMatch = false;

    for (let secondWordIndex = 0; secondWordIndex < secondWordCharacters.length; secondWordIndex++) {
      // Search the second word for a matching character
      if (characterFromFirstWord === secondWordCharacters[secondWordIndex]) {
        secondWordCharacters.splice(secondWordIndex, 1);
        foundMatch = true;

        // Exit early since a match was found
        break;
      }
    }

    // If a character is not found in the second word, not anagrams
    if (!foundMatch) {
      return false;
    }
  }

  // If second word is empty, then it is an anagram
  if (secondWordCharacters.length === 0) {
    return true;
  }

  return false;
}

