using System;
using System.Collections.Generic;

public class Solution {
    public bool AreAnagramsBruteForce(string firstWord, string secondWord) {
        List<string> allPermutations = GeneratePermutations(firstWord);

        // Iterate through all permutations to see if a match exists.
        foreach (string permutation in allPermutations) {
            if (permutation == secondWord) {
                return true;
            }
        }

        return false;
    }

    private List<string> GeneratePermutations(string word) {
        List<string> permutations = new List<string>();
        GeneratePermutationsHelper(word.ToCharArray(), 0, permutations);
        return permutations;
    }

    private void GeneratePermutationsHelper(char[] wordCharacters, int currentIndex, List<string> allPermutations) {
        if (currentIndex == wordCharacters.Length) {
            // Base case: Add the permuted word to our collection.
            allPermutations.Add(new string(wordCharacters));
            return;
        }

        for (int i = currentIndex; i < wordCharacters.Length; i++) {
            Swap(wordCharacters, currentIndex, i);
            GeneratePermutationsHelper(wordCharacters, currentIndex + 1, allPermutations);

            // Backtrack to generate next permutation.
            Swap(wordCharacters, currentIndex, i);
        }
    }

    private void Swap(char[] wordCharacters, int firstIndex, int secondIndex) {
        char temporary = wordCharacters[firstIndex];
        wordCharacters[firstIndex] = wordCharacters[secondIndex];
        wordCharacters[secondIndex] = temporary;
    }
}

