func areAnagramsBruteForce(firstString string, secondString string) bool {
	firstStringLength := len(firstString)
	secondStringLength := len(secondString)

	// If lengths differ, they cannot be anagrams
	if firstStringLength != secondStringLength {
		return false
	}

	secondStringAsRunes := []rune(secondString)

	for i := 0; i < firstStringLength; i++ {
		letterFound := false
		for j := 0; j < len(secondStringAsRunes); j++ {
			if rune(firstString[i]) == secondStringAsRunes[j] {
				// Mark that we found the letter and remove it
				letterFound = true
				secondStringAsRunes = append(secondStringAsRunes[:j], secondStringAsRunes[j+1:]...)
				break
			}
		}

		// If letter from the first string isn't in the second, not anagrams
		if !letterFound {
			return false
		}
	}

	//If the second string is now empty, it's an anagram
	return len(secondStringAsRunes) == 0
}

