function validAnagram(firstString: string, secondString: string): boolean {
  // Anagrams must have the same length.
  if (firstString.length !== secondString.length) {
    return false;
  }

  // Use a map to store character counts for the first string.
  const firstStringCharacterCounts = new Map<string, number>();
  for (const char of firstString) {
    firstStringCharacterCounts.set(char, (firstStringCharacterCounts.get(char) || 0) + 1);
  }

  // Decrement counts based on the second string.  If a count goes negative,
  // it means secondString has more of that character than firstString.
  for (const char of secondString) {
    if (!firstStringCharacterCounts.has(char)) {
      return false;
    }

    firstStringCharacterCounts.set(char, firstStringCharacterCounts.get(char)! - 1);

    //If the count ever drops below 0, return false.
    if (firstStringCharacterCounts.get(char)! < 0) {
        return false;
    }
  }

  // Verify all character counts are zero.
  for (const count of firstStringCharacterCounts.values()) {
    //If count is not zero, strings are not anagrams
    if (count !== 0) {
      return false;
    }
  }

  return true;
}

